// ---- DataStore Preferences (modern replacement for SharedPreferences) ----
// Dependencies:
// implementation("androidx.datastore:datastore-preferences:1.1.0")

import android.content.Context
import androidx.datastore.preferences.core.*
import androidx.datastore.preferences.preferencesDataStore
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map

// ---- DataStore Keys ----
object PreferencesKeys {
    val USER_NAME = stringPreferencesKey("user_name")
    val USER_AGE = intPreferencesKey("user_age")
    val IS_LOGGED_IN = booleanPreferencesKey("is_logged_in")
    val LAST_LEVEL = intPreferencesKey("last_level")
    val HIGH_SCORE = intPreferencesKey("high_score")
    val SOUND_ENABLED = booleanPreferencesKey("sound_enabled")
    val MUSIC_ENABLED = booleanPreferencesKey("music_enabled")
    val PLAYER_NAME = stringPreferencesKey("player_name")
    val APP_THEME = stringPreferencesKey("app_theme")
}

// ---- DataStore instance ----
val Context.dataStore by preferencesDataStore(name = "game_preferences")

// ---- Preferences Repository ----
class PreferencesRepository(private val context: Context) {
    private val dataStore = context.dataStore

    // ---- Read preferences ----
    fun getUserName(): Flow<String> {
        return dataStore.data.map { preferences ->
            preferences[PreferencesKeys.USER_NAME] ?: "Guest"
        }
    }

    fun getUserAge(): Flow<Int> {
        return dataStore.data.map { preferences ->
            preferences[PreferencesKeys.USER_AGE] ?: 0
        }
    }

    fun isLoggedIn(): Flow<Boolean> {
        return dataStore.data.map { preferences ->
            preferences[PreferencesKeys.IS_LOGGED_IN] ?: false
        }
    }

    fun getHighScore(): Flow<Int> {
        return dataStore.data.map { preferences ->
            preferences[PreferencesKeys.HIGH_SCORE] ?: 0
        }
    }

    fun getPlayerName(): Flow<String> {
        return dataStore.data.map { preferences ->
            preferences[PreferencesKeys.PLAYER_NAME] ?: ""
        }
    }

    // ---- Write preferences ----
    suspend fun saveUserName(name: String) {
        dataStore.edit { preferences ->
            preferences[PreferencesKeys.USER_NAME] = name
        }
    }

    suspend fun saveUserAge(age: Int) {
        dataStore.edit { preferences ->
            preferences[PreferencesKeys.USER_AGE] = age
        }
    }

    suspend fun setLoggedIn(loggedIn: Boolean) {
        dataStore.edit { preferences ->
            preferences[PreferencesKeys.IS_LOGGED_IN] = loggedIn
        }
    }

    suspend fun saveHighScore(score: Int) {
        dataStore.edit { preferences ->
            val currentHigh = preferences[PreferencesKeys.HIGH_SCORE] ?: 0
            if (score > currentHigh) {
                preferences[PreferencesKeys.HIGH_SCORE] = score
            }
        }
    }

    suspend fun savePlayerName(name: String) {
        dataStore.edit { preferences ->
            preferences[PreferencesKeys.PLAYER_NAME] = name
        }
    }

    suspend fun clearAll() {
        dataStore.edit { preferences ->
            preferences.clear()
        }
    }
}

// ---- ViewModel with Preferences ----
class PreferencesViewModel(private val repository: PreferencesRepository) : ViewModel() {
    private val _userName = MutableStateFlow("")
    val userName: StateFlow<String> = _userName.asStateFlow()

    private val _userAge = MutableStateFlow(0)
    val userAge: StateFlow<Int> = _userAge.asStateFlow()

    private val _isLoggedIn = MutableStateFlow(false)
    val isLoggedIn: StateFlow<Boolean> = _isLoggedIn.asStateFlow()

    private val _highScore = MutableStateFlow(0)
    val highScore: StateFlow<Int> = _highScore.asStateFlow()

    private val _playerName = MutableStateFlow("")
    val playerName: StateFlow<String> = _playerName.asStateFlow()

    init {
        loadPreferences()
    }

    private fun loadPreferences() {
        viewModelScope.launch {
            repository.getUserName().collect { name ->
                _userName.value = name
            }
        }

        viewModelScope.launch {
            repository.getUserAge().collect { age ->
                _userAge.value = age
            }
        }

        viewModelScope.launch {
            repository.isLoggedIn().collect { loggedIn ->
                _isLoggedIn.value = loggedIn
            }
        }

        viewModelScope.launch {
            repository.getHighScore().collect { score ->
                _highScore.value = score
            }
        }

        viewModelScope.launch {
            repository.getPlayerName().collect { name ->
                _playerName.value = name
            }
        }
    }

    fun saveUserName(name: String) {
        viewModelScope.launch {
            repository.saveUserName(name)
        }
    }

    fun saveUserAge(age: Int) {
        viewModelScope.launch {
            repository.saveUserAge(age)
        }
    }

    fun setLoggedIn(loggedIn: Boolean) {
        viewModelScope.launch {
            repository.setLoggedIn(loggedIn)
        }
    }

    fun saveHighScore(score: Int) {
        viewModelScope.launch {
            repository.saveHighScore(score)
        }
    }

    fun savePlayerName(name: String) {
        viewModelScope.launch {
            repository.savePlayerName(name)
        }
    }

    fun clearAll() {
        viewModelScope.launch {
            repository.clearAll()
            loadPreferences()
        }
    }
}

// ---- UI ----
@Composable
fun PreferencesScreen() {
    val context = LocalContext.current
    val repository = remember { PreferencesRepository(context) }
    val viewModel: PreferencesViewModel = viewModel { PreferencesViewModel(repository) }

    val userName by viewModel.userName.collectAsState()
    val userAge by viewModel.userAge.collectAsState()
    val isLoggedIn by viewModel.isLoggedIn.collectAsState()
    val highScore by viewModel.highScore.collectAsState()
    val playerName by viewModel.playerName.collectAsState()

    var nameInput by remember { mutableStateOf("") }
    var ageInput by remember { mutableStateOf("") }
    var scoreInput by remember { mutableStateOf("") }

    Scaffold(
        topBar = { TopAppBar { Text("SharedPreferences / DataStore") } }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // ---- Display preferences ----
            Card(
                modifier = Modifier.fillMaxWidth(),
                elevation = CardDefaults.cardElevation(4.dp)
            ) {
                Column(
                    modifier = Modifier.padding(16.dp),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Text("User Preferences:", style = MaterialTheme.typography.titleMedium)
                    Text("User Name: $userName")
                    Text("User Age: $userAge")
                    Text("Logged In: ${if (isLoggedIn) "Yes" else "No"}")
                    Text("High Score: $highScore")
                    Text("Player Name: $playerName")
                }
            }

            // ---- Save user name ----
            OutlinedTextField(
                value = nameInput,
                onValueChange = { nameInput = it },
                label = { Text("User Name") },
                modifier = Modifier.fillMaxWidth()
            )

            Button(
                onClick = {
                    if (nameInput.isNotBlank()) {
                        viewModel.saveUserName(nameInput)
                        nameInput = ""
                    }
                },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Save User Name")
            }

            // ---- Save user age ----
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                OutlinedTextField(
                    value = ageInput,
                    onValueChange = { ageInput = it },
                    label = { Text("Age") },
                    modifier = Modifier.weight(1f),
                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
                )

                Button(
                    onClick = {
                        ageInput.toIntOrNull()?.let { age ->
                            viewModel.saveUserAge(age)
                            ageInput = ""
                        }
                    }
                ) {
                    Text("Save Age")
                }
            }

            // ---- Save high score ----
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                OutlinedTextField(
                    value = scoreInput,
                    onValueChange = { scoreInput = it },
                    label = { Text("Score") },
                    modifier = Modifier.weight(1f),
                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
                )

                Button(
                    onClick = {
                        scoreInput.toIntOrNull()?.let { score ->
                            viewModel.saveHighScore(score)
                            scoreInput = ""
                        }
                    }
                ) {
                    Text("Save Score")
                }
            }

            // ---- Toggle login ----
            Button(
                onClick = { viewModel.setLoggedIn(!isLoggedIn) },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text(if (isLoggedIn) "Logout" else "Login")
            }

            // ---- Clear all ----
            Button(
                onClick = { viewModel.clearAll() },
                modifier = Modifier.fillMaxWidth(),
                colors = ButtonDefaults.buttonColors(
                    containerColor = MaterialTheme.colorScheme.error
                )
            ) {
                Text("Clear All Preferences")
            }
        }
    }
}

