package com.example.datastore

import android.content.Context
import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.unit.dp
import androidx.datastore.preferences.core.*
import androidx.datastore.preferences.preferencesDataStore
import androidx.lifecycle.ViewModel
import androidx.lifecycle.compose.viewModel
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.launch

val Context.dataStore by preferencesDataStore(name = "app_preferences")

object PrefKeys {
    val USER_NAME = stringPreferencesKey("user_name")
    val USER_AGE = intPreferencesKey("user_age")
    val HIGH_SCORE = intPreferencesKey("high_score")
}

class PrefRepository(private val context: Context) {
    private val dataStore = context.dataStore

    fun getUserName(): Flow<String> = dataStore.data.map { it[PrefKeys.USER_NAME] ?: "" }
    fun getUserAge(): Flow<Int> = dataStore.data.map { it[PrefKeys.USER_AGE] ?: 0 }
    fun getHighScore(): Flow<Int> = dataStore.data.map { it[PrefKeys.HIGH_SCORE] ?: 0 }

    suspend fun saveUserName(name: String) { dataStore.edit { it[PrefKeys.USER_NAME] = name } }
    suspend fun saveUserAge(age: Int) { dataStore.edit { it[PrefKeys.USER_AGE] = age } }
    suspend fun saveHighScore(score: Int) { dataStore.edit { it[PrefKeys.HIGH_SCORE] = score } }
    suspend fun clearAll() { dataStore.edit { it.clear() } }
}

class PrefViewModel(private val repository: PrefRepository) : ViewModel() {
    private val _userName = MutableStateFlow("")
    val userName: StateFlow<String> = _userName.asStateFlow()

    private val _userAge = MutableStateFlow(0)
    val userAge: StateFlow<Int> = _userAge.asStateFlow()

    private val _highScore = MutableStateFlow(0)
    val highScore: StateFlow<Int> = _highScore.asStateFlow()

    init {
        viewModelScope.launch {
            repository.getUserName().collect { _userName.value = it }
        }
        viewModelScope.launch {
            repository.getUserAge().collect { _userAge.value = it }
        }
        viewModelScope.launch {
            repository.getHighScore().collect { _highScore.value = it }
        }
    }

    fun saveUserName(name: String) { viewModelScope.launch { repository.saveUserName(name) } }
    fun saveUserAge(age: Int) { viewModelScope.launch { repository.saveUserAge(age) } }
    fun saveHighScore(score: Int) { viewModelScope.launch { repository.saveHighScore(score) } }
    fun clearAll() { viewModelScope.launch { repository.clearAll() } }
}

@Composable
fun DataStoreApp() {
    val context = LocalContext.current
    val repository = remember { PrefRepository(context) }
    val viewModel: PrefViewModel = viewModel { PrefViewModel(repository) }

    val userName by viewModel.userName.collectAsState()
    val userAge by viewModel.userAge.collectAsState()
    val highScore by viewModel.highScore.collectAsState()

    var nameInput by remember { mutableStateOf("") }
    var ageInput by remember { mutableStateOf("") }
    var scoreInput by remember { mutableStateOf("") }

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        Card(
            modifier = Modifier.fillMaxWidth(),
            elevation = CardDefaults.cardElevation(4.dp)
        ) {
            Column(modifier = Modifier.padding(16.dp)) {
                Text("Saved Preferences:", style = MaterialTheme.typography.titleMedium)
                Text("Name: $userName")
                Text("Age: $userAge")
                Text("High Score: $highScore")
            }
        }

        OutlinedTextField(value = nameInput, onValueChange = { nameInput = it }, label = { Text("Name") })
        Button(onClick = { if (nameInput.isNotBlank()) { viewModel.saveUserName(nameInput); nameInput = "" } }) {
            Text("Save Name")
        }

        OutlinedTextField(value = ageInput, onValueChange = { ageInput = it }, label = { Text("Age") })
        Button(onClick = { ageInput.toIntOrNull()?.let { viewModel.saveUserAge(it); ageInput = "" } }) {
            Text("Save Age")
        }

        OutlinedTextField(value = scoreInput, onValueChange = { scoreInput = it }, label = { Text("Score") })
        Button(onClick = { scoreInput.toIntOrNull()?.let { viewModel.saveHighScore(it); scoreInput = "" } }) {
            Text("Save Score")
        }

        Button(onClick = { viewModel.clearAll() }) {
            Text("Clear All")
        }
    }
}
